import React, { useState } from 'react';
import axios from 'axios';

export default function Dashboard() {
  const [flightNumber, setFlightNumber] = useState('');
  const [data, setData] = useState([]);

  const fetchData = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/flights/${flightNumber}`
      );
      setData(res.data);
    } catch (err) {
      console.error(err);
      alert('Error fetching flight data');
    }
  };

  return (
    <div className="container">
      <h1>🛰️ Live Flight Tracker (OpenSky)</h1>

      <div className="search-box">
        <input
          placeholder="Enter Flight Number (e.g. AI101)"
          value={flightNumber}
          onChange={(e) => setFlightNumber(e.target.value)}
        />
        <button onClick={fetchData}>Track</button>
      </div>

      <div style={{ marginTop: 30 }}>
        {data.length === 0 && <p>No live flights found</p>}

        {data.map((flight, index) => (
          <div key={index} className="card">
            <p><b>Callsign:</b> {flight.callsign}</p>
            <p><b>Country:</b> {flight.country}</p>
            <p><b>Latitude:</b> {flight.latitude}</p>
            <p><b>Longitude:</b> {flight.longitude}</p>
            <p><b>Altitude:</b> {flight.altitude}</p>
            <p><b>Velocity:</b> {flight.velocity}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
